const __pageData = JSON.parse('{"title":"数据库设计模式：从范式到反范式","description":"系统阐述关系数据库范式理论、反范化策略与数据仓库建模，深入探讨 CQRS、Event Sourcing 在数据库层的映射，并结合 Node.js 生态中的 Prisma、TypeORM 等工具给出多租户、软删除、审计日志与时间序列数据的工程实践方案。","frontmatter":{"title":"数据库设计模式：从范式到反范式","description":"系统阐述关系数据库范式理论、反范化策略与数据仓库建模，深入探讨 CQRS、Event Sourcing 在数据库层的映射，并结合 Node.js 生态中的 Prisma、TypeORM 等工具给出多租户、软删除、审计日志与时间序列数据的工程实践方案。","date":"2026-05-01T00:00:00.000Z","tags":["database","normalization","denormalization","prisma","cqrs","event-sourcing","multi-tenancy","timeseries","schema-design"],"category":"engineering"},"headers":[],"relativePath":"database-orm/11-database-design-patterns.md","filePath":"database-orm/11-database-design-patterns.md","lastUpdated":1777741461000}');
